  ('heelevel3-9e7ddffc-moex-00106', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-111-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '根據IS-LM與AD-AS模型，當政府大幅調高基本工資時，在其他條件不變下，如果投資對利率 愈敏感，則：', '["短期均衡實質GDP與一般物價水準的降幅皆愈大", "短期均衡實質GDP與一般物價水準的降幅皆愈小", "短期均衡實質GDP的減幅愈大且一般物價水準的升幅愈小", "短期均衡實質GDP的減幅愈小且一般物價水準的升幅愈大 32260、32560 32960、33060"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "329", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00107', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-111-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '當IS曲線愈陡峭，則總合需求曲線愈  ①  ；當LM曲線愈平坦，則貨幣需求利率彈性愈  ②  。', '["平坦；小", "平坦；大", "陡峭；小", "陡峭；大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "329", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00108', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-111-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '根據梭羅（SolowModel）模型，假設A國和B國的生產函數、人口成長率與資本折舊率都相同， 但A國儲蓄率大於B國。若兩國都沒有技術進步的情況下，則下列敘述何者正確？', '["A國目前的每人平均產出一定大於B國", "A國目前的每人平均產出一定等於B國", "長期時，A國的每人平均產出成長率一定大於B國", "長期時，A國的每人平均產出成長率一定等於B國"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "329", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00109', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-111-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '在開放體系下，假設邊際進口傾向為0.1，邊際稅率為0.25，邊際消費傾向為0.8，若自發性投資 增加200萬，則均衡產出增加：', '["100萬", "1000萬", "400萬", "500萬"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "329", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00110', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-111-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '關於景氣循環的敘述，下列何者正確？', '["收縮期包括衰退期與復甦期", "景氣循環是短期經濟波動的現象", "擴張期是指一個頂峰至另一個頂峰的期間", "景氣循環指標是由行政院主計總處估計並發布"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "329", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00111', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-111-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '下列何者不影響資本使用者的成本？', '["實質利率", "折舊率", "資本實質價格之預期變動率", "資本的邊際生產力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "329", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00112', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-111-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '根據庫茲內茲（Kuznets）的實證發現，民眾長期的邊際消費傾向與平均消費傾向會隨所得增加而 如何變動？', '["邊際消費傾向增加與平均消費傾向增加", "邊際消費傾向減少與平均消費傾向減少", "邊際消費傾向不變與平均消費傾向不變", "邊際消費傾向增加與平均消費傾向不變"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "329", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00113', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-111-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '令橫軸變數為實質 GDP，縱軸變數為利率。假設實質貨幣需求只決定於利率。就 IS-LM模型 而言：', '["LM線為一水平線，且財政政策有效", "LM線為一水平線，且財政政策無效", "LM線為一垂直線，且財政政策有效", "LM線為一垂直線，且財政政策無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "329", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
